import { useState, useEffect, useCallback } from "react";
import { api, setToken, clearToken } from "./api.js";

// ── Brand Logo (embedded) ─────────────────────────────────────────────────
const LOGO_SRC = "data:image/png;base64,";

// ── Constants ─────────────────────────────────────────────────────────────
const STAGES         = ["New","Contacted","Qualified","Proposal","Closed Won","Closed Lost"];
const ROLES          = { super_admin:"Super Admin", admin:"Admin", sales_manager:"Sales Manager", sales_rep:"Sales Rep", viewer:"Viewer" };
const SOURCES        = ["Inbound","Referral","Cold Outreach","Event","Agency","Social Media"];
const ACTIVITY_TYPES = ["Call","Email","Meeting","Note","Task"];
const ACT_ICONS      = { Call:"📞", Email:"✉️", Meeting:"🤝", Note:"📝", Task:"✅" };

const STAGE_COLORS  = { "New":"#64748b","Contacted":"#3b82f6","Qualified":"#f59e0b","Proposal":"#f97316","Closed Won":"#10b981","Closed Lost":"#ef4444" };
const ROLE_COLORS   = { super_admin:"#c084fc", admin:"#ff6b35", sales_manager:"#34d399", sales_rep:"#fbbf24", viewer:"#94a3b8" };
const MANAGER_ROLES = ["super_admin","admin","sales_manager"];

const DEFAULT_PROPERTIES = ["OMNES Lifestyle","OMNES Magazine","OMNES Digital","OMNES Travel","OMNES Business"];
const DEFAULT_CATEGORIES = ["Automotive","Luxury","Technology","Hospitality","Finance","Sports","FMCG","Real Estate"];

const fmt   = n => n >= 1000 ? `AED ${(n/1000).toFixed(0)}K` : `AED ${n}`;
const today = () => new Date().toISOString().slice(0,10);

// ── Export helpers ─────────────────────────────────────────────────────────
function exportCSV(rows, filename) {
  if (!rows.length) return;
  const headers = Object.keys(rows[0]);
  const csv = [headers.join(","), ...rows.map(r => headers.map(h => `"${String(r[h]??''  ).replace(/"/g,'""')}"`).join(","))].join("\n");
  const a = document.createElement("a"); a.href = URL.createObjectURL(new Blob([csv],{type:"text/csv"})); a.download = filename; a.click();
}

function exportPDF(title, htmlContent) {
  const win = window.open("","_blank","width=900,height=700");
  win.document.write(`<!DOCTYPE html><html><head><title>${title}</title>
    <style>body{font-family:Arial,sans-serif;padding:32px;color:#111;font-size:13px;}h1{font-size:22px;margin-bottom:4px;}.sub{color:#666;margin-bottom:24px;font-size:12px;}table{width:100%;border-collapse:collapse;margin-top:16px;}th{background:#1e293b;color:#fff;padding:8px 12px;text-align:left;font-size:12px;}td{padding:8px 12px;border-bottom:1px solid #e2e8f0;font-size:12px;}tr:nth-child(even) td{background:#f8fafc;}.badge{display:inline-block;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:600;}@media print{body{padding:16px;}}</style>
    </head><body>${htmlContent}</body></html>`);
  win.document.close();
  setTimeout(() => win.print(), 400);
}

// ── CSS ────────────────────────────────────────────────────────────────────
const CSS = `
  @import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@300;400;500;600;700&family=Syne:wght@600;700;800&display=swap');
  *{box-sizing:border-box;margin:0;padding:0;}body{background:#0a0f1e;}
  ::-webkit-scrollbar{width:4px;height:4px;}::-webkit-scrollbar-track{background:#0f1629;}::-webkit-scrollbar-thumb{background:#2d3a5c;border-radius:2px;}
  input,select,textarea{font-family:'DM Sans',sans-serif;}
  .nav-item{display:flex;align-items:center;gap:10px;padding:10px 16px;border-radius:10px;cursor:pointer;transition:all .2s;color:#94a3b8;font-size:14px;font-weight:500;border:none;background:none;width:100%;text-align:left;}
  .nav-item:hover{background:rgba(255,255,255,.06);color:#e2e8f0;}
  .nav-item.active{background:linear-gradient(135deg,#ff5a1f18,#e6390010);color:#ff6b35;border:1px solid #ff5a1f33;}
  .card{background:#0f1629;border:1px solid #1e293b;border-radius:16px;padding:24px;}
  .btn{padding:9px 18px;border-radius:8px;border:none;cursor:pointer;font-size:13px;font-weight:600;font-family:'DM Sans',sans-serif;transition:all .2s;display:inline-flex;align-items:center;gap:6px;}
  .btn:disabled{opacity:.5;cursor:not-allowed;}
  .btn-primary{background:linear-gradient(135deg,#ff5a1f,#e63900);color:#fff;}.btn-primary:hover:not(:disabled){opacity:.9;transform:translateY(-1px);}
  .btn-ghost{background:rgba(255,255,255,.06);color:#94a3b8;border:1px solid #1e293b;}.btn-ghost:hover:not(:disabled){background:rgba(255,255,255,.1);color:#e2e8f0;}
  .btn-danger{background:#ef444420;color:#f87171;border:1px solid #ef444433;}
  .btn-success{background:#10b98120;color:#34d399;border:1px solid #10b98133;}
  .btn-export{background:#0f2a1a;color:#34d399;border:1px solid #10b98133;}.btn-export:hover{background:#10b98122;}
  .badge{display:inline-block;padding:3px 10px;border-radius:20px;font-size:11px;font-weight:600;letter-spacing:.5px;}
  .input{background:#0a0f1e;border:1px solid #1e293b;border-radius:8px;padding:9px 12px;color:#e2e8f0;font-size:14px;width:100%;outline:none;transition:border .2s;}
  .input:focus{border-color:#ff5a1f;}select.input option{background:#0f1629;}
  .modal-bg{position:fixed;inset:0;background:rgba(0,0,0,.75);display:flex;align-items:center;justify-content:center;z-index:100;backdrop-filter:blur(4px);}
  .modal{background:#0f1629;border:1px solid #1e293b;border-radius:20px;padding:32px;width:540px;max-height:90vh;overflow-y:auto;}
  .table-row{display:grid;align-items:center;padding:14px 20px;border-bottom:1px solid #1e293b11;transition:background .15s;cursor:pointer;}.table-row:hover{background:rgba(255,255,255,.03);}
  .pipeline-col{flex:1;min-width:190px;background:#0a0f1e;border:1px solid #1e293b;border-radius:14px;padding:16px;}
  .pipeline-card{background:#0f1629;border:1px solid #1e293b;border-radius:10px;padding:14px;margin-bottom:10px;cursor:pointer;transition:all .2s;}.pipeline-card:hover{border-color:#ff5a1f55;transform:translateY(-2px);}
  .notif{position:fixed;top:24px;right:24px;z-index:999;padding:14px 20px;border-radius:12px;font-size:13px;font-weight:500;animation:slideIn .3s ease;}
  @keyframes slideIn{from{transform:translateX(100px);opacity:0}to{transform:translateX(0);opacity:1}}
  .tab{padding:8px 16px;border-radius:8px;cursor:pointer;font-size:13px;font-weight:500;color:#64748b;transition:all .2s;border:none;background:none;}.tab.active{background:#1e293b;color:#e2e8f0;}
  label{font-size:12px;font-weight:600;color:#64748b;letter-spacing:.5px;text-transform:uppercase;display:block;margin-bottom:6px;}
  .pw-strength{height:3px;border-radius:2px;transition:all .3s;margin-top:6px;}
  .section-title{font-family:'Syne',sans-serif;font-weight:700;font-size:15px;margin-bottom:20px;}
  .spinner{display:inline-block;width:18px;height:18px;border:2px solid #1e293b;border-top-color:#ff5a1f;border-radius:50%;animation:spin .7s linear infinite;}
  @keyframes spin{to{transform:rotate(360deg)}}
  .error-banner{background:#ef444420;border:1px solid #ef444433;border-radius:10px;padding:12px 16px;color:#f87171;font-size:13px;margin-bottom:16px;}
`;

// ══════════════════════════════════════════════════════════════════════════
// ROOT APP
// ══════════════════════════════════════════════════════════════════════════
export default function App() {
  const [currentUser, setCurrentUser] = useState(null);
  const [authChecked, setAuthChecked] = useState(false);
  const [view, setView]       = useState("dashboard");
  const [notification, setNotification] = useState(null);

  // ── Data ────────────────────────────────────────────────────────────────
  const [users,      setUsers]      = useState([]);
  const [leads,      setLeads]      = useState([]);
  const [activities, setActivities] = useState([]);
  const [reports,    setReports]    = useState(null);
  const [auditLog,   setAuditLog]   = useState([]);
  const [categories, setCategories] = useState(DEFAULT_CATEGORIES);
  const [properties, setProperties] = useState(DEFAULT_PROPERTIES);
  const [loading,    setLoading]    = useState(false);

  // ── UI ──────────────────────────────────────────────────────────────────
  const [selectedLead,    setSelectedLead]    = useState(null);
  const [showAddLead,     setShowAddLead]     = useState(false);
  const [showAddUser,     setShowAddUser]     = useState(false);
  const [showChangePw,    setShowChangePw]    = useState(false);
  const [filterStage,     setFilterStage]     = useState("All");
  const [filterAssignee,  setFilterAssignee]  = useState("All");
  const [searchQ,         setSearchQ]         = useState("");

  const notify = (msg, type="success") => { setNotification({msg,type}); setTimeout(()=>setNotification(null),3500); };

  // ── Session restore ──────────────────────────────────────────────────────
  useEffect(() => {
    const savedToken = sessionStorage.getItem("omnes_token");
    const savedUser  = sessionStorage.getItem("omnes_user");
    if (savedToken && savedUser) {
      setToken(savedToken);
      setCurrentUser(JSON.parse(savedUser));
    }
    setAuthChecked(true);
  }, []);

  // ── Load settings from API (falls back to defaults if not yet saved) ──────
  useEffect(() => {
    if (!currentUser) return;
    api.settings.get().then(data => {
      if (data.categories) setCategories(data.categories);
      if (data.properties) setProperties(data.properties);
    }).catch(() => {}); // silently use defaults on failure
  }, [currentUser?.id]);

  const saveCategories = async (val) => {
    setCategories(val);
    try { await api.settings.save({ categories: val }); } catch {}
  };
  const saveProperties = async (val) => {
    setProperties(val);
    try { await api.settings.save({ properties: val }); } catch {}
  };

  // ── Load data on login ───────────────────────────────────────────────────
  useEffect(() => { if (currentUser) loadAll(); }, [currentUser?.id]);

  const loadAll = async () => {
    setLoading(true);
    try {
      const [u, l, a] = await Promise.all([api.users.list(), api.leads.list(), api.activities.list()]);
      setUsers(u); setLeads(l); setActivities(a);
    } catch (err) { notify(err.message, "error"); }
    finally { setLoading(false); }
  };

  useEffect(() => {
    if (view === "reports" && currentUser) api.reports.summary().then(setReports).catch(()=>{});
    if (view === "audit"   && currentUser) api.reports.audit().then(setAuditLog).catch(()=>{});
  }, [view]);

  // ── Auth ─────────────────────────────────────────────────────────────────
  const handleLogin = async (email, password) => {
    const res = await api.auth.login(email, password);
    setToken(res.token);
    sessionStorage.setItem("omnes_token", res.token);
    sessionStorage.setItem("omnes_user",  JSON.stringify(res.user));
    setCurrentUser(res.user);
    return res;
  };

  const handleLogout = async () => {
    try { await api.auth.logout(); } catch {}
    clearToken();
    sessionStorage.removeItem("omnes_token");
    sessionStorage.removeItem("omnes_user");
    setCurrentUser(null);
    setLeads([]); setUsers([]); setActivities([]);
    setView("dashboard");
  };

  // ── RBAC ─────────────────────────────────────────────────────────────────
  const canAccess = (feature) => {
    if (!currentUser) return false;
    const r = currentUser.role;
    if (feature === "userManagement") return ["super_admin","admin"].includes(r);
    if (feature === "allLeads")       return MANAGER_ROLES.includes(r);
    if (feature === "editLeads")      return r !== "viewer";
    if (feature === "reports")        return MANAGER_ROLES.includes(r);
    if (feature === "auditLog")       return r === "super_admin";
    if (feature === "settings")       return ["super_admin","admin"].includes(r);
    return true;
  };

  // ── Filtered leads ────────────────────────────────────────────────────────
  const visibleLeads = leads.filter(l => {
    if (!canAccess("allLeads") && currentUser && l.assigned_to !== currentUser.id) return false;
    if (filterStage    !== "All" && l.stage       !== filterStage)    return false;
    if (filterAssignee !== "All" && l.assigned_to !== filterAssignee) return false;
    if (searchQ && !`${l.company} ${l.contact} ${l.category}`.toLowerCase().includes(searchQ.toLowerCase())) return false;
    return true;
  });

  // ── Exports ───────────────────────────────────────────────────────────────
  const exportLeadsCSV = () => {
    exportCSV(visibleLeads.map(l => ({
      Company:l.company, Contact:l.contact, Email:l.email, Phone:l.phone,
      Stage:l.stage, "Value (AED)":l.value, Probability:l.probability+"%",
      Source:l.source, Category:l.category, Property:l.property,
      Type:l.deal_type, "Assigned To":l.assigned_to_name||"", Created:l.created_at?.slice(0,10),
    })), `OMNES_Leads_${today()}.csv`);
    notify("Leads exported to CSV!");
  };

  const exportLeadsPDF = () => {
    const totalVal = visibleLeads.reduce((s,l)=>s+Number(l.value),0);
    const rows = visibleLeads.map(l=>`<tr><td><b>${l.company}</b><br><span style="color:#666">${l.contact||""}</span></td><td>${l.property||""}</td><td><span class="badge" style="background:${STAGE_COLORS[l.stage]}22;color:${STAGE_COLORS[l.stage]}">${l.stage}</span></td><td><b>AED ${Number(l.value).toLocaleString()}</b></td><td>${l.probability}%</td><td>${l.assigned_to_name||""}</td><td>${l.created_at?.slice(0,10)||""}</td></tr>`).join("");
    exportPDF("OMNES CRM – Leads Report", `<h1>OMNES Media Group CRM</h1><p class="sub">Leads Report · ${visibleLeads.length} records · Total Pipeline: AED ${totalVal.toLocaleString()}</p><table><thead><tr><th>Company</th><th>Property</th><th>Stage</th><th>Value</th><th>Prob.</th><th>Assigned To</th><th>Created</th></tr></thead><tbody>${rows}</tbody></table>`);
    notify("PDF opened for printing!");
  };

  const exportPipelinePDF = () => {
    const blocks = STAGES.map(stage => {
      const sl = leads.filter(l=>l.stage===stage);
      const total = sl.reduce((s,l)=>s+Number(l.value),0);
      const rows = sl.map(l=>`<tr><td>${l.company}</td><td>${l.contact||""}</td><td>AED ${Number(l.value).toLocaleString()}</td><td>${l.probability}%</td><td>${l.assigned_to_name||""}</td></tr>`).join("");
      return `<h3 style="margin-top:24px;color:${STAGE_COLORS[stage]}">${stage} · ${sl.length} deals · AED ${total.toLocaleString()}</h3>${sl.length?`<table><thead><tr><th>Company</th><th>Contact</th><th>Value</th><th>Prob.</th><th>Assigned</th></tr></thead><tbody>${rows}</tbody></table>`:"<p style='color:#888'>No deals.</p>"}`;
    }).join("");
    exportPDF("OMNES CRM – Pipeline Report", `<h1>OMNES Media Group CRM</h1><p class="sub">Pipeline Report · ${new Date().toLocaleString()}</p>${blocks}`);
    notify("PDF opened for printing!");
  };

  // ── Loading / Auth screens ────────────────────────────────────────────────
  if (!authChecked) return <div style={{height:"100vh",background:"#0a0f1e",display:"flex",alignItems:"center",justifyContent:"center"}}><div className="spinner" /></div>;
  if (!currentUser) return <><style>{CSS}</style><LoginScreen onLogin={handleLogin} /></>;
  if (currentUser.mustChangePw) return <><style>{CSS}</style><ForcePwChange onSave={async(cur,nw)=>{ await api.auth.changePassword(cur,nw); const u={...currentUser,mustChangePw:false}; setCurrentUser(u); sessionStorage.setItem("omnes_user",JSON.stringify(u)); notify("Password updated!"); }} /></>;

  const NAV = [
    {id:"dashboard", icon:"⊞", label:"Dashboard"},
    {id:"pipeline",  icon:"◫", label:"Pipeline"},
    {id:"leads",     icon:"◈", label:"Leads & Deals"},
    {id:"activities",icon:"◷", label:"Activities"},
    ...(canAccess("reports")        ? [{id:"reports",  icon:"◉", label:"Reports"}]         : []),
    ...(canAccess("userManagement") ? [{id:"users",    icon:"◎", label:"Users"}]            : []),
    ...(canAccess("settings")       ? [{id:"settings", icon:"⚙", label:"Settings"}]         : []),
    ...(canAccess("auditLog")       ? [{id:"audit",    icon:"⊙", label:"Audit Log"}]        : []),
  ];

  const PAGE_TITLES = {dashboard:"Dashboard",pipeline:"Sales Pipeline",leads:"Leads & Deals",activities:"Activity Log",reports:"Reports",users:"User Management",settings:"Settings",audit:"Audit Log"};

  return (
    <div style={{display:"flex",height:"100vh",fontFamily:"'DM Sans',sans-serif",background:"#0a0f1e",color:"#e2e8f0"}}>
      <style>{CSS}</style>

      {/* Sidebar */}
      <div style={{width:224,background:"#080c1a",borderRight:"1px solid #1e293b",display:"flex",flexDirection:"column",padding:"24px 12px",flexShrink:0}}>
        <div style={{padding:"0 4px 20px",borderBottom:"1px solid #1e293b22",marginBottom:8}}>
          <img src={LOGO_SRC} alt="OMNES Media Group" style={{width:170,display:"block",marginBottom:6}} />
          <div style={{fontSize:10,color:"#475569",fontWeight:600,letterSpacing:1.5}}>CRM PLATFORM</div>
        </div>
        <nav style={{flex:1,display:"flex",flexDirection:"column",gap:2}}>
          {NAV.map(item => (
            <button key={item.id} className={`nav-item ${view===item.id?"active":""}`} onClick={()=>setView(item.id)}>
              <span style={{fontSize:15}}>{item.icon}</span>{item.label}
            </button>
          ))}
        </nav>
        <div style={{borderTop:"1px solid #1e293b22",paddingTop:14,display:"flex",alignItems:"center",gap:10}}>
          <Avatar name={currentUser.name} size={34}/>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontSize:13,fontWeight:600,color:"#e2e8f0",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{currentUser.name.split(" ")[0]}</div>
            <div style={{fontSize:11,color:"#475569"}}>{ROLES[currentUser.role]}</div>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:4}}>
            <button title="Change Password" className="btn btn-ghost" style={{padding:"3px 7px",fontSize:11}} onClick={()=>setShowChangePw(true)}>🔑</button>
            <button title="Logout" className="btn btn-ghost" style={{padding:"3px 7px",fontSize:11}} onClick={handleLogout}>↩</button>
          </div>
        </div>
      </div>

      {/* Main */}
      <div style={{flex:1,overflow:"auto",display:"flex",flexDirection:"column"}}>
        <div style={{padding:"18px 32px",borderBottom:"1px solid #1e293b",display:"flex",alignItems:"center",justifyContent:"space-between",background:"#080c1a",gap:12,flexShrink:0}}>
          <div>
            <h1 style={{fontFamily:"Syne,sans-serif",fontSize:20,fontWeight:700,color:"#f1f5f9"}}>{PAGE_TITLES[view]}</h1>
            <div style={{fontSize:12,color:"#475569",marginTop:2}}>{new Date().toDateString()}</div>
          </div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap",justifyContent:"flex-end",alignItems:"center"}}>
            {view==="leads" && canAccess("editLeads") && <>
              <button className="btn btn-export" onClick={exportLeadsCSV}>⬇ CSV</button>
              <button className="btn btn-export" onClick={exportLeadsPDF}>⬇ PDF</button>
              <button className="btn btn-primary" onClick={()=>setShowAddLead(true)}>+ New Deal</button>
            </>}
            {view==="pipeline" && <>
              <button className="btn btn-export" onClick={exportPipelinePDF}>⬇ Pipeline PDF</button>
              {canAccess("editLeads") && <button className="btn btn-primary" onClick={()=>setShowAddLead(true)}>+ New Deal</button>}
            </>}
            {view==="activities" && <button className="btn btn-export" onClick={()=>{ exportCSV(activities.map(a=>({Type:a.type,Note:a.note,Date:a.created_at?.slice(0,10),Company:a.lead_company||"","Logged By":a.user_name||""})),`OMNES_Activities_${today()}.csv`); notify("Exported!"); }}>⬇ CSV</button>}
            {view==="users" && canAccess("userManagement") && <button className="btn btn-primary" onClick={()=>setShowAddUser(true)}>+ Invite User</button>}
            {loading && <div className="spinner"/>}
          </div>
        </div>

        <div style={{flex:1,padding:"28px 32px",overflow:"auto"}}>
          {view==="dashboard"  && <Dashboard leads={leads} users={users} activities={activities} setView={setView}/>}
          {view==="pipeline"   && <Pipeline  leads={visibleLeads} users={users} onSelect={setSelectedLead}/>}
          {view==="leads"      && <LeadsTable leads={visibleLeads} users={users} onSelect={setSelectedLead} filterStage={filterStage} setFilterStage={setFilterStage} filterAssignee={filterAssignee} setFilterAssignee={setFilterAssignee} searchQ={searchQ} setSearchQ={setSearchQ} canAccess={canAccess}/>}
          {view==="activities" && <ActivityLog activities={activities} leads={leads} users={users}/>}
          {view==="reports"    && <Reports data={reports} leads={leads}/>}
          {view==="users"      && <UserManagement users={users} setUsers={setUsers} currentUser={currentUser} notify={notify} showAddUser={showAddUser} setShowAddUser={setShowAddUser}/>}
          {view==="settings"   && <SettingsPanel categories={categories} properties={properties} setCategories={saveCategories} setProperties={saveProperties} leads={leads} notify={notify} currentUser={currentUser}/>}
          {view==="audit"      && <AuditLogView log={auditLog}/>}
        </div>
      </div>

      {/* Modals */}
      {selectedLead && <LeadDetail lead={selectedLead} users={users} activities={activities} categories={categories} properties={properties} canAccess={canAccess} currentUser={currentUser} onClose={()=>setSelectedLead(null)} notify={notify}
        onLeadUpdated={updated=>{setLeads(p=>p.map(l=>l.id===updated.id?updated:l));setSelectedLead(updated);}}
        onActivityAdded={act=>setActivities(p=>[act,...p])}/>}
      {showAddLead  && <AddLeadModal  users={users} currentUser={currentUser} categories={categories} properties={properties} onClose={()=>setShowAddLead(false)} onSave={async data=>{ const l=await api.leads.create(data); setLeads(p=>[l,...p]); setShowAddLead(false); notify("Deal created!"); }}/>}
      {showAddUser  && <AddUserModal  onClose={()=>setShowAddUser(false)} onSave={async data=>{ const res=await api.users.invite(data); setUsers(p=>[...p,res.user]); setShowAddUser(false); notify(`Invited! Temp pw: ${res.tempPassword}`); }}/>}
      {showChangePw && <ChangePwModal onClose={()=>setShowChangePw(false)} onSave={async(cur,nw)=>{ await api.auth.changePassword(cur,nw); setShowChangePw(false); notify("Password updated!"); }}/>}

      {notification && (
        <div className="notif" style={{background:notification.type==="success"?"#10b98120":"#ef444420",border:`1px solid ${notification.type==="success"?"#10b98155":"#ef444455"}`,color:notification.type==="success"?"#34d399":"#f87171"}}>
          {notification.msg}
        </div>
      )}
    </div>
  );
}

// ── Avatar ────────────────────────────────────────────────────────────────
function Avatar({name="?",size=36}) {
  const initials = name.split(" ").map(w=>w[0]).slice(0,2).join("");
  const colors = ["#ff5a1f","#e63900","#10b981","#f59e0b","#ef4444","#06b6d4"];
  const color  = colors[name.charCodeAt(0)%colors.length];
  return <div style={{width:size,height:size,borderRadius:"50%",background:color+"33",border:`2px solid ${color}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:size*.35,fontWeight:700,color,flexShrink:0}}>{initials}</div>;
}

// ── Login ─────────────────────────────────────────────────────────────────
function LoginScreen({onLogin}) {
  const [step,setStep]=useState("email"); const [email,setEmail]=useState(""); const [pw,setPw]=useState(""); const [showPw,setShowPw]=useState(false); const [err,setErr]=useState(""); const [busy,setBusy]=useState(false);
  const goNext=()=>{ if(!email.includes("@")){setErr("Please enter a valid email.");return;} setStep("password");setErr(""); };
  const doLogin=async()=>{ setBusy(true);setErr(""); try{await onLogin(email,pw);}catch(e){setErr(e.message);}finally{setBusy(false);} };
  return (
    <div style={{height:"100vh",background:"#0a0f1e",display:"flex",alignItems:"center",justifyContent:"center"}}>
      <div style={{width:420}}>
        <div style={{textAlign:"center",marginBottom:32}}>
          <img src={LOGO_SRC} alt="OMNES Media Group" style={{width:220,display:"block",margin:"0 auto 10px"}}/>
          <div style={{fontSize:11,color:"#475569",fontWeight:600,letterSpacing:2}}>CRM PLATFORM</div>
        </div>
        <div style={{background:"#0f1629",border:"1px solid #1e293b",borderRadius:20,padding:36}}>
          {step==="email"?<>
            <div style={{fontFamily:"Syne,sans-serif",fontSize:20,fontWeight:700,color:"#f1f5f9",marginBottom:6}}>Welcome back</div>
            <div style={{fontSize:13,color:"#475569",marginBottom:24}}>Sign in with your work email</div>
            <div style={{marginBottom:20}}><label>Work Email</label>
              <input className="input" type="email" placeholder="you@omnesmedia.com" value={email} onChange={e=>{setEmail(e.target.value);setErr("");}} onKeyDown={e=>e.key==="Enter"&&goNext()} autoFocus/>
              {err&&<div style={{fontSize:12,color:"#f87171",marginTop:8}}>{err}</div>}
            </div>
            <button className="btn btn-primary" style={{width:"100%",justifyContent:"center",padding:"12px"}} onClick={goNext}>Continue →</button>
          </>:<>
            <button className="btn btn-ghost" style={{marginBottom:20,fontSize:12}} onClick={()=>{setStep("email");setErr("");setPw("");}}>← Back</button>
            <div style={{fontFamily:"Syne,sans-serif",fontSize:18,fontWeight:700,color:"#f1f5f9",marginBottom:4}}>Enter password</div>
            <div style={{fontSize:13,color:"#475569",marginBottom:24}}>{email}</div>
            <div style={{marginBottom:20}}><label>Password</label>
              <div style={{position:"relative"}}>
                <input className="input" type={showPw?"text":"password"} placeholder="Your password" value={pw} onChange={e=>{setPw(e.target.value);setErr("");}} onKeyDown={e=>e.key==="Enter"&&!busy&&doLogin()} autoFocus style={{paddingRight:40}}/>
                <button onClick={()=>setShowPw(v=>!v)} style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#475569",fontSize:14}}>{showPw?"🙈":"👁"}</button>
              </div>
              {err&&<div style={{fontSize:12,color:"#f87171",marginTop:8}}>{err}</div>}
            </div>
            <button className="btn btn-primary" style={{width:"100%",justifyContent:"center",padding:"12px"}} onClick={doLogin} disabled={busy}>{busy?<><div className="spinner"/>&nbsp;Signing in…</>:"Sign In"}</button>
          </>}
        </div>
      </div>
    </div>
  );
}

// ── Force Password Change ─────────────────────────────────────────────────
function ForcePwChange({onSave}) {
  const [cur,setCur]=useState(""); const [pw,setPw]=useState(""); const [conf,setConf]=useState(""); const [err,setErr]=useState(""); const [busy,setBusy]=useState(false);
  const strength=pw.length<6?0:pw.length<8?1:/[A-Z]/.test(pw)&&/[0-9]/.test(pw)?3:2;
  const sc=["#ef4444","#f59e0b","#3b82f6","#10b981"];
  const submit=async()=>{ if(pw.length<8){setErr("Min 8 characters.");return;} if(pw!==conf){setErr("Passwords don't match.");return;} setBusy(true); try{await onSave(cur,pw);}catch(e){setErr(e.message);setBusy(false);} };
  return <div style={{height:"100vh",background:"#0a0f1e",display:"flex",alignItems:"center",justifyContent:"center"}}>
    <div style={{width:400,background:"#0f1629",border:"1px solid #ff5a1f55",borderRadius:20,padding:36}}>
      <div style={{fontSize:24,marginBottom:8}}>🔐</div>
      <div style={{fontFamily:"Syne,sans-serif",fontSize:18,fontWeight:700,color:"#f1f5f9",marginBottom:6}}>Set Your Password</div>
      <div style={{fontSize:13,color:"#475569",marginBottom:24}}>An admin reset your password. Please set a new one to continue.</div>
      {[{l:"Current Password",v:cur,s:setCur},{l:"New Password",v:pw,s:setPw,str:true},{l:"Confirm Password",v:conf,s:setConf}].map(f=>(
        <div key={f.l} style={{marginBottom:14}}><label>{f.l}</label>
          <input className="input" type="password" value={f.v} onChange={e=>{f.s(e.target.value);setErr("");}}/>
          {f.str&&pw&&<><div className="pw-strength" style={{width:`${(strength/3)*100}%`,background:sc[strength]}}/><div style={{fontSize:11,color:sc[strength],marginTop:4}}>{"Too short,Weak,Good,Strong".split(",")[strength]}</div></>}
        </div>))}
      {err&&<div style={{fontSize:12,color:"#f87171",marginBottom:12}}>{err}</div>}
      <button className="btn btn-primary" style={{width:"100%",justifyContent:"center",padding:"12px"}} onClick={submit} disabled={busy}>{busy?"Saving…":"Set Password & Continue"}</button>
    </div></div>;
}

// ── Change Password Modal ─────────────────────────────────────────────────
function ChangePwModal({onClose,onSave}) {
  const [cur,setCur]=useState(""); const [pw,setPw]=useState(""); const [conf,setConf]=useState(""); const [err,setErr]=useState(""); const [busy,setBusy]=useState(false);
  const submit=async()=>{ if(pw.length<8){setErr("Min 8 characters.");return;} if(pw!==conf){setErr("Passwords don't match.");return;} setBusy(true); try{await onSave(cur,pw);onClose();}catch(e){setErr(e.message);setBusy(false);} };
  return <div className="modal-bg" onClick={e=>e.target===e.currentTarget&&onClose()}>
    <div className="modal" style={{width:420}}>
      <div style={{fontFamily:"Syne,sans-serif",fontSize:18,fontWeight:700,marginBottom:24}}>Change Password</div>
      {[{l:"Current Password",v:cur,s:setCur},{l:"New Password",v:pw,s:setPw},{l:"Confirm New",v:conf,s:setConf}].map(f=>(
        <div key={f.l} style={{marginBottom:16}}><label>{f.l}</label><input className="input" type="password" value={f.v} onChange={e=>{f.s(e.target.value);setErr("");}}/></div>))}
      {err&&<div style={{fontSize:12,color:"#f87171",marginBottom:12}}>{err}</div>}
      <div style={{display:"flex",gap:10,justifyContent:"flex-end"}}><button className="btn btn-ghost" onClick={onClose}>Cancel</button><button className="btn btn-primary" onClick={submit} disabled={busy}>{busy?"Saving…":"Update"}</button></div>
    </div></div>;
}

// ── Dashboard ─────────────────────────────────────────────────────────────
function Dashboard({leads,users,activities,setView}) {
  const total=leads.reduce((s,l)=>s+Number(l.value),0);
  const won=leads.filter(l=>l.stage==="Closed Won").reduce((s,l)=>s+Number(l.value),0);
  const active=leads.filter(l=>!["Closed Won","Closed Lost"].includes(l.stage));
  const pipeline=active.reduce((s,l)=>s+Number(l.value),0);
  const convRate=leads.length?Math.round(leads.filter(l=>l.stage==="Closed Won").length/leads.length*100):0;
  const recent=[...activities].sort((a,b)=>new Date(b.created_at)-new Date(a.created_at)).slice(0,5);
  return <div style={{display:"flex",flexDirection:"column",gap:24}}>
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:16}}>
      {[{l:"Active Pipeline",v:fmt(pipeline),s:`${active.length} deals`,c:"#ff6b35"},{l:"Revenue Won",v:fmt(won),s:"Closed won",c:"#34d399"},{l:"Conversion",v:convRate+"%",s:"Win rate",c:"#f59e0b"},{l:"Total Deals",v:leads.length,s:users.filter(u=>u.active).length+" reps",c:"#c084fc"}].map((s,i)=>(
        <div key={i} style={{background:"#0f1629",border:"1px solid #1e293b",borderRadius:16,padding:"20px 24px"}}>
          <div style={{fontSize:11,color:"#64748b",fontWeight:600,letterSpacing:.5,textTransform:"uppercase"}}>{s.l}</div>
          <div style={{fontSize:28,fontWeight:700,color:s.c,fontFamily:"Syne,sans-serif",marginTop:8}}>{s.v}</div>
          <div style={{fontSize:12,color:"#475569",marginTop:4}}>{s.s}</div>
        </div>))}
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:24}}>
      <div className="card"><div className="section-title">Pipeline by Stage</div>
        {STAGES.map(stage=>{const sv=leads.filter(l=>l.stage===stage).reduce((s,l)=>s+Number(l.value),0);return(
          <div key={stage} style={{marginBottom:14}}>
            <div style={{display:"flex",justifyContent:"space-between",marginBottom:6,fontSize:13}}><span style={{color:"#94a3b8"}}>{stage}</span><span style={{fontWeight:600,color:STAGE_COLORS[stage]}}>{fmt(sv)}</span></div>
            <div style={{height:6,background:"#1e293b",borderRadius:3,overflow:"hidden"}}><div style={{height:"100%",width:`${total?(sv/total)*100:0}%`,background:STAGE_COLORS[stage],borderRadius:3}}/></div>
          </div>);})}
      </div>
      <div className="card"><div className="section-title">Recent Activities</div>
        <div style={{display:"flex",flexDirection:"column",gap:14}}>
          {recent.map(act=>(
            <div key={act.id} style={{display:"flex",gap:12,alignItems:"flex-start"}}>
              <div style={{width:32,height:32,borderRadius:"50%",background:"#1e293b",display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,flexShrink:0}}>{ACT_ICONS[act.type]}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontSize:13,fontWeight:500,color:"#e2e8f0"}}>{act.type} — {act.lead_company}</div>
                <div style={{fontSize:12,color:"#64748b",marginTop:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{act.note}</div>
                <div style={{fontSize:11,color:"#475569",marginTop:3}}>{act.user_name} · {act.created_at?.slice(0,10)}</div>
              </div>
            </div>))}
        </div>
      </div>
    </div>
    <div className="card">
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <div className="section-title" style={{margin:0}}>Top Deals</div>
        <button className="btn btn-ghost" style={{fontSize:12}} onClick={()=>setView("leads")}>View All →</button>
      </div>
      {[...leads].sort((a,b)=>Number(b.value)-Number(a.value)).slice(0,5).map(lead=>(
        <div key={lead.id} style={{display:"flex",alignItems:"center",padding:"12px 0",borderBottom:"1px solid #1e293b22",gap:12}}>
          <Avatar name={lead.company} size={38}/>
          <div style={{flex:1}}><div style={{fontSize:14,fontWeight:600,color:"#e2e8f0"}}>{lead.company}</div><div style={{fontSize:12,color:"#64748b"}}>{lead.property} · {lead.assigned_to_name}</div></div>
          <span className="badge" style={{background:STAGE_COLORS[lead.stage]+"22",color:STAGE_COLORS[lead.stage]}}>{lead.stage}</span>
          <div style={{fontSize:15,fontWeight:700,color:"#ff6b35",minWidth:90,textAlign:"right"}}>{fmt(lead.value)}</div>
        </div>))}
    </div>
  </div>;
}

// ── Pipeline ──────────────────────────────────────────────────────────────
function Pipeline({leads,users,onSelect}) {
  return <div style={{display:"flex",gap:14,overflowX:"auto",paddingBottom:16}}>
    {STAGES.map(stage=>{
      const sl=leads.filter(l=>l.stage===stage);
      const total=sl.reduce((s,l)=>s+Number(l.value),0);
      return <div key={stage} className="pipeline-col">
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
          <div style={{display:"flex",alignItems:"center",gap:8}}><div style={{width:8,height:8,borderRadius:"50%",background:STAGE_COLORS[stage]}}/><span style={{fontSize:13,fontWeight:700,color:"#94a3b8"}}>{stage}</span></div>
          <span style={{fontSize:11,fontWeight:700,color:STAGE_COLORS[stage],background:STAGE_COLORS[stage]+"22",padding:"2px 7px",borderRadius:10}}>{sl.length}</span>
        </div>
        <div style={{fontSize:12,color:"#475569",marginBottom:14,fontWeight:600}}>{fmt(total)}</div>
        {sl.map(lead=>{const user=users.find(u=>u.id===lead.assigned_to);return(
          <div key={lead.id} className="pipeline-card" onClick={()=>onSelect(lead)}>
            <div style={{fontSize:13,fontWeight:700,color:"#e2e8f0",marginBottom:6}}>{lead.company}</div>
            <div style={{fontSize:11,color:"#64748b",marginBottom:10}}>{lead.property}</div>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{fontSize:13,fontWeight:700,color:"#ff6b35"}}>{fmt(lead.value)}</span>
              {user&&<Avatar name={user.name} size={22}/>}
            </div>
            <div style={{marginTop:10,height:3,background:"#1e293b",borderRadius:2}}><div style={{height:"100%",width:`${lead.probability}%`,background:STAGE_COLORS[stage],borderRadius:2}}/></div>
            <div style={{fontSize:10,color:"#475569",marginTop:4}}>{lead.probability}% probability</div>
          </div>);})}
      </div>;})}
  </div>;
}

// ── Leads Table ────────────────────────────────────────────────────────────
function LeadsTable({leads,users,onSelect,filterStage,setFilterStage,filterAssignee,setFilterAssignee,searchQ,setSearchQ,canAccess}) {
  return <div style={{display:"flex",flexDirection:"column",gap:16}}>
    <div style={{display:"flex",gap:12,flexWrap:"wrap"}}>
      <input className="input" placeholder="Search…" value={searchQ} onChange={e=>setSearchQ(e.target.value)} style={{width:220}}/>
      <select className="input" value={filterStage} onChange={e=>setFilterStage(e.target.value)} style={{width:150}}><option value="All">All Stages</option>{STAGES.map(s=><option key={s}>{s}</option>)}</select>
      {canAccess("allLeads")&&<select className="input" value={filterAssignee} onChange={e=>setFilterAssignee(e.target.value)} style={{width:160}}><option value="All">All Reps</option>{users.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}</select>}
    </div>
    <div className="card" style={{padding:0,overflow:"hidden"}}>
      <div style={{display:"grid",gridTemplateColumns:"2fr 1.5fr 1fr 1fr 1fr 1fr",padding:"12px 20px",borderBottom:"1px solid #1e293b",fontSize:11,fontWeight:700,color:"#475569",letterSpacing:.5,textTransform:"uppercase"}}>
        <span>Company</span><span>Property</span><span>Stage</span><span>Value</span><span>Assigned</span><span>Created</span>
      </div>
      {leads.length===0&&<div style={{padding:40,textAlign:"center",color:"#475569"}}>No deals found.</div>}
      {leads.map(lead=>(
        <div key={lead.id} className="table-row" style={{gridTemplateColumns:"2fr 1.5fr 1fr 1fr 1fr 1fr"}} onClick={()=>onSelect(lead)}>
          <div><div style={{fontSize:14,fontWeight:600,color:"#e2e8f0"}}>{lead.company}</div><div style={{fontSize:12,color:"#64748b"}}>{lead.contact}</div></div>
          <div style={{fontSize:13,color:"#94a3b8"}}>{lead.property}</div>
          <div><span className="badge" style={{background:STAGE_COLORS[lead.stage]+"22",color:STAGE_COLORS[lead.stage]}}>{lead.stage}</span></div>
          <div style={{fontSize:14,fontWeight:700,color:"#ff6b35"}}>{fmt(lead.value)}</div>
          <div style={{display:"flex",alignItems:"center",gap:8}}>{lead.assigned_to_name&&<><Avatar name={lead.assigned_to_name} size={24}/><span style={{fontSize:12,color:"#64748b"}}>{lead.assigned_to_name.split(" ")[0]}</span></>}</div>
          <div style={{fontSize:12,color:"#475569"}}>{lead.created_at?.slice(0,10)}</div>
        </div>))}
    </div>
  </div>;
}

// ── Activity Log ──────────────────────────────────────────────────────────
function ActivityLog({activities}) {
  const sorted=[...activities].sort((a,b)=>new Date(b.created_at)-new Date(a.created_at));
  return <div className="card" style={{padding:0,overflow:"hidden"}}>
    <div style={{padding:"20px 24px",borderBottom:"1px solid #1e293b",fontFamily:"Syne,sans-serif",fontWeight:700,fontSize:15}}>All Activities <span style={{fontSize:13,color:"#475569",fontFamily:"DM Sans,sans-serif",fontWeight:400}}>({sorted.length})</span></div>
    {sorted.map(act=>(
      <div key={act.id} style={{display:"flex",gap:16,padding:"16px 24px",borderBottom:"1px solid #1e293b22",alignItems:"flex-start"}}>
        <div style={{width:38,height:38,borderRadius:10,background:"#1e293b",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0}}>{ACT_ICONS[act.type]}</div>
        <div style={{flex:1}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div style={{fontSize:14,fontWeight:600,color:"#e2e8f0"}}>{act.type} — <span style={{color:"#ff6b35"}}>{act.lead_company}</span></div>
            <div style={{fontSize:12,color:"#475569"}}>{act.created_at?.slice(0,10)}</div>
          </div>
          <div style={{fontSize:13,color:"#94a3b8",marginTop:4}}>{act.note}</div>
          <div style={{fontSize:11,color:"#475569",marginTop:6}}>By {act.user_name}</div>
        </div>
      </div>))}
  </div>;
}

// ── Reports ───────────────────────────────────────────────────────────────
function Reports({data,leads}) {
  if(!data) return <div style={{color:"#475569",padding:40,textAlign:"center"}}>Loading…<div className="spinner" style={{margin:"16px auto"}}/></div>;
  const {summary,byStage,byProperty,bySource,repPerf}=data;
  const maxP=Math.max(...(byProperty||[]).map(p=>Number(p.total)),1);
  return <div style={{display:"flex",flexDirection:"column",gap:24}}>
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:16}}>
      {[{l:"Pipeline Value",v:fmt(summary.pipeline_value||0),c:"#ff6b35"},{l:"Revenue Won",v:fmt(summary.won_value||0),c:"#34d399"},{l:"Win Rate",v:summary.total_deals>0?Math.round(summary.won_count/summary.total_deals*100)+"%":"0%",c:"#f59e0b"},{l:"Active Deals",v:summary.active_deals||0,c:"#c084fc"}].map((s,i)=>(
        <div key={i} style={{background:"#0f1629",border:"1px solid #1e293b",borderRadius:16,padding:"20px 24px"}}>
          <div style={{fontSize:11,color:"#64748b",fontWeight:600,letterSpacing:.5,textTransform:"uppercase"}}>{s.l}</div>
          <div style={{fontSize:28,fontWeight:700,color:s.c,fontFamily:"Syne,sans-serif",marginTop:8}}>{s.v}</div>
        </div>))}
    </div>
    <div className="card">
      <div className="section-title">Rep Performance</div>
      <div style={{display:"grid",gridTemplateColumns:"2fr 1fr 1fr 1fr 1fr",padding:"8px 0",borderBottom:"1px solid #1e293b",fontSize:11,fontWeight:700,color:"#475569",textTransform:"uppercase",gap:12}}>
        <span>Rep</span><span>Deals</span><span>Won</span><span>Pipeline</span><span>Activities</span>
      </div>
      {(repPerf||[]).map(rep=>(
        <div key={rep.id} style={{display:"grid",gridTemplateColumns:"2fr 1fr 1fr 1fr 1fr",padding:"14px 0",borderBottom:"1px solid #1e293b11",alignItems:"center",gap:12}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}><Avatar name={rep.name} size={32}/><div><div style={{fontSize:13,fontWeight:600,color:"#e2e8f0"}}>{rep.name}</div><div style={{fontSize:11,color:"#475569"}}>{ROLES[rep.role]}</div></div></div>
          <div style={{fontSize:14,fontWeight:700,color:"#94a3b8"}}>{rep.deals}</div>
          <div style={{fontSize:13,fontWeight:700,color:"#34d399"}}>{fmt(rep.won_value||0)}</div>
          <div style={{fontSize:13,fontWeight:700,color:"#ff6b35"}}>{fmt(rep.pipeline_value||0)}</div>
          <div style={{fontSize:14,fontWeight:700,color:"#fbbf24"}}>{rep.activities}</div>
        </div>))}
    </div>
    <div className="card"><div className="section-title">Revenue by Media Property</div>
      {(byProperty||[]).map(p=>(
        <div key={p.property} style={{marginBottom:16}}>
          <div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}><span style={{fontSize:13,color:"#94a3b8"}}>{p.property}</span><span style={{fontSize:13,fontWeight:700,color:"#ff6b35"}}>{fmt(p.total||0)} <span style={{color:"#475569"}}>({p.count})</span></span></div>
          <div style={{height:8,background:"#1e293b",borderRadius:4,overflow:"hidden"}}><div style={{height:"100%",width:`${(Number(p.total)/maxP)*100}%`,background:"linear-gradient(90deg,#ff5a1f,#e63900)",borderRadius:4}}/></div>
        </div>))}
    </div>
    <div className="card"><div className="section-title">Leads by Source</div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:14}}>
        {(bySource||[]).map(s=>(
          <div key={s.source} style={{background:"#0a0f1e",borderRadius:12,padding:"16px 18px",border:"1px solid #1e293b"}}>
            <div style={{fontSize:22,fontWeight:800,fontFamily:"Syne,sans-serif",color:"#ff6b35"}}>{s.count}</div>
            <div style={{fontSize:12,color:"#64748b",marginTop:4}}>{s.source}</div>
          </div>))}
      </div>
    </div>
  </div>;
}

// ── User Management ────────────────────────────────────────────────────────
function UserManagement({users,setUsers,currentUser,notify,showAddUser,setShowAddUser}) {
  const toggleActive=async id=>{
    if(id===currentUser.id){notify("Cannot deactivate yourself.","error");return;}
    const u=users.find(u=>u.id===id);
    try{await api.users.update(id,{active:!u.active});setUsers(p=>p.map(x=>x.id===id?{...x,active:!x.active}:x));notify("Status updated.");}
    catch(e){notify(e.message,"error");}
  };
  const resetPw=async(id,tempPw)=>{ try{await api.users.resetPassword(id,tempPw);notify(`Reset done. Temp: ${tempPw}`);}catch(e){notify(e.message,"error");} };
  return <div style={{display:"flex",flexDirection:"column",gap:16}}>
    <div style={{display:"flex",gap:10,flexWrap:"wrap"}}>{Object.entries(ROLES).map(([k,v])=><span key={k} className="badge" style={{background:ROLE_COLORS[k]+"22",color:ROLE_COLORS[k]}}>{v}</span>)}</div>
    <div className="card" style={{padding:0,overflow:"hidden"}}>
      <div style={{display:"grid",gridTemplateColumns:"2fr 2fr 1.2fr 1fr 1fr 1.2fr",padding:"12px 20px",borderBottom:"1px solid #1e293b",fontSize:11,fontWeight:700,color:"#475569",textTransform:"uppercase",letterSpacing:.5}}>
        <span>User</span><span>Email</span><span>Role</span><span>Team</span><span>Last Login</span><span>Actions</span>
      </div>
      {users.map(user=>(
        <div key={user.id} className="table-row" style={{gridTemplateColumns:"2fr 2fr 1.2fr 1fr 1fr 1.2fr",cursor:"default"}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}><Avatar name={user.name} size={34}/><div>
            <div style={{fontSize:14,fontWeight:600,color:"#e2e8f0"}}>{user.name}</div>
            {user.id===currentUser.id&&<span style={{fontSize:10,color:"#ff6b35"}}>● You</span>}
            {user.must_change_pw&&<span style={{fontSize:10,color:"#f59e0b"}}> ⚠ Pending pw</span>}
          </div></div>
          <div style={{fontSize:13,color:"#64748b"}}>{user.email}</div>
          <div><span className="badge" style={{background:ROLE_COLORS[user.role]+"22",color:ROLE_COLORS[user.role]}}>{ROLES[user.role]}</span></div>
          <div style={{fontSize:13,color:"#64748b"}}>{user.team}</div>
          <div style={{fontSize:12,color:"#475569"}}>{user.last_login?new Date(user.last_login).toLocaleDateString():"—"}</div>
          <div style={{display:"flex",gap:6}}>
            <button className="btn" style={{fontSize:11,padding:"4px 10px",background:user.active?"#10b98120":"#ef444420",color:user.active?"#34d399":"#f87171",border:`1px solid ${user.active?"#10b98133":"#ef444433"}`}} onClick={()=>toggleActive(user.id)}>{user.active?"Active":"Inactive"}</button>
            {currentUser.role==="super_admin"&&user.id!==currentUser.id&&<button className="btn btn-ghost" style={{fontSize:11,padding:"4px 10px"}} onClick={()=>{const t=prompt(`Temp password for ${user.name}:`,"Temp@1234");if(t)resetPw(user.id,t);}}>🔑</button>}
          </div>
        </div>))}
    </div>
    {showAddUser&&<AddUserModal onClose={()=>setShowAddUser(false)} onSave={async data=>{try{const res=await api.users.invite(data);setUsers(p=>[...p,res.user]);setShowAddUser(false);notify(`Invited! Temp pw: ${res.tempPassword}`);}catch(e){notify(e.message,"error");}}}/>}
  </div>;
}

// ── Audit Log ─────────────────────────────────────────────────────────────
function AuditLogView({log}) {
  return <div className="card" style={{padding:0,overflow:"hidden"}}>
    <div style={{padding:"20px 24px",borderBottom:"1px solid #1e293b",fontFamily:"Syne,sans-serif",fontWeight:700,fontSize:15}}>Audit Log <span style={{fontSize:13,color:"#475569",fontFamily:"DM Sans,sans-serif",fontWeight:400}}>({log.length})</span></div>
    <div style={{display:"grid",gridTemplateColumns:"2fr 1.5fr 2fr 1.5fr",padding:"12px 20px",borderBottom:"1px solid #1e293b",fontSize:11,fontWeight:700,color:"#475569",textTransform:"uppercase",letterSpacing:.5}}><span>User</span><span>Action</span><span>Target</span><span>Date</span></div>
    {log.map(e=>(
      <div key={e.id} style={{display:"grid",gridTemplateColumns:"2fr 1.5fr 2fr 1.5fr",padding:"12px 20px",borderBottom:"1px solid #1e293b11",alignItems:"center"}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>{e.user_name&&<Avatar name={e.user_name} size={26}/>}<span style={{fontSize:13,color:"#e2e8f0"}}>{e.user_name||"System"}</span></div>
        <span style={{fontSize:12,fontWeight:600,color:"#ff6b35"}}>{e.action}</span>
        <span style={{fontSize:12,color:"#64748b"}}>{e.target}</span>
        <span style={{fontSize:12,color:"#475569"}}>{new Date(e.created_at).toLocaleString()}</span>
      </div>))}
  </div>;
}

// ── Settings Panel ────────────────────────────────────────────────────────
function SettingsPanel({categories,properties,setCategories,setProperties,leads,notify,currentUser}) {
  const [tab,setTab]=useState("properties");
  return <div style={{display:"flex",flexDirection:"column",gap:24}}>
    <div style={{display:"flex",gap:4,background:"#080c1a",borderRadius:12,padding:4,width:"fit-content",border:"1px solid #1e293b"}}>
      {[{id:"properties",label:"⬡  Business Units"},{id:"categories",label:"◈  Lead Categories"}].map(t=>(
        <button key={t.id} className={`tab ${tab===t.id?"active":""}`} style={{borderRadius:8,padding:"8px 20px",fontWeight:600}} onClick={()=>setTab(t.id)}>{t.label}</button>))}
    </div>
    {tab==="properties"&&<ListEditor title="OMNES Business Units" subtitle="Your media properties — appear in every deal form and Reports." items={properties} setItems={setProperties} leads={leads} leadsKey="property" colorFn={i=>["#ff5a1f","#f97316","#34d399","#f59e0b","#f472b6","#38bdf8","#fb923c"][i%7]} notify={notify} auditLabel="Business Unit" placeholder="e.g. OMNES Events"/>}
    {tab==="categories"&&<ListEditor title="Lead Categories" subtitle="Industry categories that classify the type of advertiser." items={categories} setItems={setCategories} leads={leads} leadsKey="category" colorFn={i=>["#f59e0b","#10b981","#ff5a1f","#8b5cf6","#ef4444","#06b6d4","#84cc16","#f97316"][i%8]} notify={notify} auditLabel="Category" placeholder="e.g. Retail"/>}
  </div>;
}

function ListEditor({title,subtitle,items,setItems,leads,leadsKey,colorFn,notify,auditLabel,placeholder}) {
  const [newItem,setNewItem]=useState(""); const [editingIdx,setEditingIdx]=useState(null); const [editVal,setEditVal]=useState(""); const [confirmDel,setConfirmDel]=useState(null);
  const usageCount=item=>leads.filter(l=>l[leadsKey]===item).length;
  const handleAdd=()=>{ const v=newItem.trim(); if(!v)return; if(items.map(i=>i.toLowerCase()).includes(v.toLowerCase())){notify(`"${v}" already exists.`,"error");return;} setItems([...items,v]); setNewItem(""); notify(`"${v}" added!`); };
  const handleRename=idx=>{ const v=editVal.trim(); if(!v)return; const old=items[idx]; if(v===old){setEditingIdx(null);return;} setItems(items.map((item,i)=>i===idx?v:item)); setEditingIdx(null); notify(`Renamed to "${v}"!`); };
  const handleDelete=idx=>{ if(usageCount(items[idx])>0){setConfirmDel(idx);return;} doDelete(idx); };
  const doDelete=idx=>{ const item=items[idx]; setItems(items.filter((_,i)=>i!==idx)); setConfirmDel(null); notify(`"${item}" removed.`); };
  const moveUp=idx=>{ if(idx===0)return; const a=[...items]; [a[idx-1],a[idx]]=[a[idx],a[idx-1]]; setItems(a); };
  const moveDown=idx=>{ if(idx===items.length-1)return; const a=[...items]; [a[idx],a[idx+1]]=[a[idx+1],a[idx]]; setItems(a); };
  return <div style={{display:"flex",flexDirection:"column",gap:20}}>
    <div className="card" style={{padding:"20px 24px",display:"flex",justifyContent:"space-between",alignItems:"flex-start",gap:16}}>
      <div><div style={{fontFamily:"Syne,sans-serif",fontWeight:700,fontSize:16,color:"#f1f5f9",marginBottom:4}}>{title}</div><div style={{fontSize:13,color:"#64748b",maxWidth:500}}>{subtitle}</div></div>
      <div style={{background:"#1e293b",borderRadius:10,padding:"10px 18px",textAlign:"center",flexShrink:0}}><div style={{fontSize:22,fontWeight:800,fontFamily:"Syne,sans-serif",color:"#ff6b35"}}>{items.length}</div><div style={{fontSize:11,color:"#64748b",marginTop:2}}>Total</div></div>
    </div>
    <div className="card" style={{padding:"20px 24px"}}>
      <div style={{fontSize:12,fontWeight:700,color:"#64748b",letterSpacing:.5,textTransform:"uppercase",marginBottom:12}}>Add New {auditLabel}</div>
      <div style={{display:"flex",gap:10}}>
        <input className="input" placeholder={placeholder} value={newItem} onChange={e=>setNewItem(e.target.value)} onKeyDown={e=>e.key==="Enter"&&handleAdd()} style={{flex:1}}/>
        <button className="btn btn-primary" onClick={handleAdd}>+ Add</button>
      </div>
    </div>
    <div className="card" style={{padding:0,overflow:"hidden"}}>
      <div style={{padding:"14px 20px",borderBottom:"1px solid #1e293b",fontSize:11,fontWeight:700,color:"#475569",letterSpacing:.5,textTransform:"uppercase",display:"grid",gridTemplateColumns:"1fr auto auto",gap:12,alignItems:"center"}}>
        <span>Name</span><span style={{width:80,textAlign:"center"}}>Deals Using</span><span style={{width:140,textAlign:"right"}}>Actions</span>
      </div>
      {items.length===0&&<div style={{padding:40,textAlign:"center",color:"#475569"}}>No items yet. Add one above.</div>}
      {items.map((item,idx)=>{const count=usageCount(item);const isEditing=editingIdx===idx;return(
        <div key={item+idx} style={{display:"grid",gridTemplateColumns:"1fr auto auto",gap:12,padding:"14px 20px",borderBottom:"1px solid #1e293b11",alignItems:"center",background:isEditing?"rgba(255,90,31,0.06)":"transparent",transition:"background .2s"}}>
          <div style={{display:"flex",alignItems:"center",gap:12}}>
            <div style={{width:10,height:10,borderRadius:"50%",background:colorFn(idx),flexShrink:0}}/>
            {isEditing?<input className="input" value={editVal} onChange={e=>setEditVal(e.target.value)} onKeyDown={e=>{if(e.key==="Enter")handleRename(idx);if(e.key==="Escape")setEditingIdx(null);}} autoFocus style={{maxWidth:300}}/>:<span style={{fontSize:14,fontWeight:600,color:"#e2e8f0"}}>{item}</span>}
          </div>
          <div style={{width:80,textAlign:"center"}}>{count>0?<span style={{fontSize:12,fontWeight:700,background:"#ff5a1f20",color:"#ff6b35",padding:"3px 10px",borderRadius:10}}>{count} deal{count!==1?"s":""}</span>:<span style={{fontSize:12,color:"#334155"}}>—</span>}</div>
          <div style={{width:140,display:"flex",justifyContent:"flex-end",gap:4}}>
            {isEditing?<>
              <button className="btn btn-success" style={{padding:"4px 12px",fontSize:12}} onClick={()=>handleRename(idx)}>Save</button>
              <button className="btn btn-ghost"   style={{padding:"4px 10px",fontSize:12}} onClick={()=>setEditingIdx(null)}>✕</button>
            </>:<>
              <button title="Move Up"   className="btn btn-ghost"  style={{padding:"4px 8px",fontSize:11}}  onClick={()=>moveUp(idx)}   disabled={idx===0}>↑</button>
              <button title="Move Down" className="btn btn-ghost"  style={{padding:"4px 8px",fontSize:11}}  onClick={()=>moveDown(idx)} disabled={idx===items.length-1}>↓</button>
              <button title="Rename"    className="btn btn-ghost"  style={{padding:"4px 10px",fontSize:11}} onClick={()=>{setEditingIdx(idx);setEditVal(item);}}>✏️</button>
              <button title="Delete"    className="btn btn-danger" style={{padding:"4px 10px",fontSize:11}} onClick={()=>handleDelete(idx)}>🗑</button>
            </>}
          </div>
        </div>);})}
    </div>
    {confirmDel!==null&&<div className="modal-bg" onClick={()=>setConfirmDel(null)}>
      <div className="modal" style={{width:420}} onClick={e=>e.stopPropagation()}>
        <div style={{fontSize:32,marginBottom:12}}>⚠️</div>
        <div style={{fontFamily:"Syne,sans-serif",fontSize:18,fontWeight:700,color:"#f1f5f9",marginBottom:8}}>Delete "{items[confirmDel]}"?</div>
        <div style={{fontSize:14,color:"#94a3b8",marginBottom:8}}><strong style={{color:"#fbbf24"}}>{usageCount(items[confirmDel])} existing deal{usageCount(items[confirmDel])!==1?"s":""}</strong> use this {auditLabel.toLowerCase()}.</div>
        <div style={{background:"#0a0f1e",border:"1px solid #f59e0b33",borderRadius:10,padding:"12px 14px",fontSize:13,color:"#fbbf24",marginBottom:20}}>Those deals keep their value but this option won't appear in new deal forms.</div>
        <div style={{display:"flex",gap:10,justifyContent:"flex-end"}}>
          <button className="btn btn-ghost"  onClick={()=>setConfirmDel(null)}>Cancel</button>
          <button className="btn btn-danger" onClick={()=>doDelete(confirmDel)}>Delete Anyway</button>
        </div>
      </div></div>}
  </div>;
}

// ── Lead Detail Modal ─────────────────────────────────────────────────────
function LeadDetail({lead,users,activities,categories,properties,canAccess,currentUser,onClose,notify,onLeadUpdated,onActivityAdded}) {
  const [tab,setTab]=useState("details"); const [editing,setEditing]=useState(false); const [form,setForm]=useState({...lead}); const [newAct,setNewAct]=useState({type:"Call",note:""}); const [busy,setBusy]=useState(false);
  const leadActs=activities.filter(a=>a.lead_id===lead.id).sort((a,b)=>new Date(b.created_at)-new Date(a.created_at));
  const saveEdit=async()=>{ setBusy(true); try{const updated=await api.leads.update(lead.id,{stage:form.stage,value:form.value,probability:form.probability,property:form.property,category:form.category,assignedTo:form.assigned_to,notes:form.notes});onLeadUpdated(updated);setEditing(false);notify("Deal updated!");}catch(e){notify(e.message,"error");}finally{setBusy(false);} };
  const logAct=async()=>{ if(!newAct.note.trim())return; setBusy(true); try{const act=await api.activities.create({leadId:lead.id,...newAct});onActivityAdded(act);setNewAct({type:"Call",note:""});notify("Activity logged!");}catch(e){notify(e.message,"error");}finally{setBusy(false);} };
  return <div className="modal-bg" onClick={e=>e.target===e.currentTarget&&onClose()}>
    <div className="modal" style={{width:660}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:20}}>
        <div><div style={{fontFamily:"Syne,sans-serif",fontSize:20,fontWeight:700,color:"#f1f5f9"}}>{lead.company}</div><div style={{fontSize:13,color:"#64748b",marginTop:4}}>{lead.contact} · {lead.email}</div></div>
        <div style={{display:"flex",gap:8,alignItems:"center"}}><span className="badge" style={{background:STAGE_COLORS[lead.stage]+"22",color:STAGE_COLORS[lead.stage]}}>{lead.stage}</span><button className="btn btn-ghost" style={{padding:"5px 10px"}} onClick={onClose}>✕</button></div>
      </div>
      <div style={{background:"linear-gradient(135deg,#ff5a1f18,#e6390010)",border:"1px solid #ff5a1f44",borderRadius:12,padding:"14px 20px",display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <div><div style={{fontSize:11,color:"#64748b",fontWeight:600,textTransform:"uppercase"}}>Deal Value</div><div style={{fontSize:26,fontWeight:800,fontFamily:"Syne,sans-serif",color:"#ff6b35"}}>{fmt(lead.value)}</div></div>
        <div style={{textAlign:"right"}}><div style={{fontSize:11,color:"#64748b",fontWeight:600,textTransform:"uppercase"}}>Win Probability</div><div style={{fontSize:26,fontWeight:800,fontFamily:"Syne,sans-serif",color:"#ff6b35"}}>{lead.probability}%</div></div>
      </div>
      <div style={{display:"flex",gap:4,marginBottom:20,borderBottom:"1px solid #1e293b",paddingBottom:12}}>
        {["details","activities"].map(t=><button key={t} className={`tab ${tab===t?"active":""}`} onClick={()=>setTab(t)}>{t==="details"?"Details":`Activities (${leadActs.length})`}</button>)}
        {canAccess("editLeads")&&tab==="details"&&<button className="btn btn-ghost" style={{marginLeft:"auto",fontSize:12,padding:"5px 14px"}} onClick={()=>setEditing(v=>!v)}>{editing?"Cancel":"✏️ Edit"}</button>}
      </div>
      {tab==="details"&&(editing?(
        <div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
            {[{l:"Stage",k:"stage",type:"select",opts:STAGES},{l:"Value (AED)",k:"value",type:"number"},{l:"Probability %",k:"probability",type:"number"},{l:"Property",k:"property",type:"select",opts:properties||[]},{l:"Category",k:"category",type:"select",opts:categories||[]},{l:"Assigned To",k:"assigned_to",type:"select",opts:users.map(u=>({v:u.id,l:u.name}))}].map(f=>(
              <div key={f.k}><label>{f.l}</label>
                {f.type==="select"?<select className="input" value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:e.target.value}))}>{f.opts?.map(o=>typeof o==="string"?<option key={o}>{o}</option>:<option key={o.v} value={o.v}>{o.l}</option>)}</select>:<input className="input" type={f.type} value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:f.type==="number"?+e.target.value:e.target.value}))}/>}
              </div>))}
            <div style={{gridColumn:"1/-1"}}><label>Notes</label><textarea className="input" rows={3} value={form.notes||""} onChange={e=>setForm(p=>({...p,notes:e.target.value}))}/></div>
          </div>
          <div style={{display:"flex",justifyContent:"flex-end",gap:8,marginTop:16}}><button className="btn btn-ghost" onClick={()=>{setEditing(false);setForm({...lead});}}>Cancel</button><button className="btn btn-primary" onClick={saveEdit} disabled={busy}>{busy?"Saving…":"Save"}</button></div>
        </div>):(
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          {[{l:"Contact",v:lead.contact},{l:"Email",v:lead.email},{l:"Phone",v:lead.phone},{l:"Source",v:lead.source},{l:"Category",v:lead.category},{l:"Property",v:lead.property},{l:"Deal Type",v:lead.deal_type},{l:"Assigned To",v:lead.assigned_to_name},{l:"Created",v:lead.created_at?.slice(0,10)}].map(f=>(
            <div key={f.l} style={{background:"#0a0f1e",borderRadius:8,padding:"10px 14px",border:"1px solid #1e293b"}}><div style={{fontSize:11,color:"#475569",fontWeight:600,marginBottom:4}}>{f.l}</div><div style={{fontSize:14,color:"#e2e8f0"}}>{f.v||"—"}</div></div>))}
          {lead.notes&&<div style={{gridColumn:"1/-1",background:"#0a0f1e",borderRadius:8,padding:"10px 14px",border:"1px solid #1e293b"}}><div style={{fontSize:11,color:"#475569",fontWeight:600,marginBottom:4}}>Notes</div><div style={{fontSize:14,color:"#94a3b8",lineHeight:1.6}}>{lead.notes}</div></div>}
        </div>))}
      {tab==="activities"&&<div>
        {canAccess("editLeads")&&<div style={{background:"#0a0f1e",border:"1px solid #1e293b",borderRadius:12,padding:16,marginBottom:16}}>
          <div style={{display:"flex",gap:10}}>
            <select className="input" value={newAct.type} onChange={e=>setNewAct(p=>({...p,type:e.target.value}))} style={{width:120}}>{ACTIVITY_TYPES.map(t=><option key={t}>{t}</option>)}</select>
            <input className="input" placeholder="Add a note…" value={newAct.note} onChange={e=>setNewAct(p=>({...p,note:e.target.value}))} onKeyDown={e=>e.key==="Enter"&&logAct()}/>
            <button className="btn btn-primary" style={{whiteSpace:"nowrap"}} onClick={logAct} disabled={busy}>Log</button>
          </div>
        </div>}
        <div style={{display:"flex",flexDirection:"column",gap:10,maxHeight:320,overflowY:"auto"}}>
          {leadActs.length===0&&<div style={{color:"#475569",textAlign:"center",padding:24}}>No activities yet.</div>}
          {leadActs.map(act=>(
            <div key={act.id} style={{display:"flex",gap:12,padding:"12px 14px",background:"#0a0f1e",borderRadius:10,border:"1px solid #1e293b"}}>
              <span style={{fontSize:18}}>{ACT_ICONS[act.type]}</span>
              <div style={{flex:1}}><div style={{display:"flex",justifyContent:"space-between"}}><span style={{fontSize:13,fontWeight:600,color:"#e2e8f0"}}>{act.type}</span><span style={{fontSize:11,color:"#475569"}}>{act.created_at?.slice(0,10)} · {act.user_name}</span></div><div style={{fontSize:13,color:"#94a3b8",marginTop:4}}>{act.note}</div></div>
            </div>))}
        </div>
      </div>}
    </div></div>;
}

// ── Add Lead Modal ────────────────────────────────────────────────────────
function AddLeadModal({users,currentUser,categories,properties,onClose,onSave}) {
  const [form,setForm]=useState({company:"",contact:"",email:"",phone:"",stage:"New",value:0,source:"Inbound",assignedTo:currentUser.id,category:(categories||[])[0]||"",property:(properties||[])[0]||"",dealType:"Direct",probability:20,notes:""});
  const [err,setErr]=useState(""); const [busy,setBusy]=useState(false);
  const submit=async()=>{ if(!form.company){setErr("Company name required.");return;} setBusy(true); try{await onSave(form);}catch(e){setErr(e.message);setBusy(false);} };
  const fields=[{l:"Company Name *",k:"company",type:"text",full:true},{l:"Contact",k:"contact",type:"text"},{l:"Email",k:"email",type:"email"},{l:"Phone",k:"phone",type:"text"},{l:"Value (AED)",k:"value",type:"number"},{l:"Probability %",k:"probability",type:"number"},{l:"Stage",k:"stage",type:"select",opts:STAGES},{l:"Source",k:"source",type:"select",opts:SOURCES},{l:"Media Property",k:"property",type:"select",opts:properties||[]},{l:"Category",k:"category",type:"select",opts:categories||[]},{l:"Deal Type",k:"dealType",type:"select",opts:["Direct","Agency"]},{l:"Assigned To",k:"assignedTo",type:"select",opts:users.map(u=>({v:u.id,l:u.name}))},{l:"Notes",k:"notes",type:"textarea",full:true}];
  return <div className="modal-bg" onClick={e=>e.target===e.currentTarget&&onClose()}><div className="modal">
    <div style={{fontFamily:"Syne,sans-serif",fontSize:18,fontWeight:700,marginBottom:24}}>New Deal</div>
    {err&&<div className="error-banner">{err}</div>}
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
      {fields.map(f=><div key={f.k} style={{gridColumn:f.full?"1/-1":undefined}}><label>{f.l}</label>
        {f.type==="select"?<select className="input" value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:e.target.value}))}>{f.opts?.map(o=>typeof o==="string"?<option key={o}>{o}</option>:<option key={o.v} value={o.v}>{o.l}</option>)}</select>:f.type==="textarea"?<textarea className="input" rows={3} value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:e.target.value}))}/>:<input className="input" type={f.type} value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:f.type==="number"?+e.target.value:e.target.value}))}/>}
      </div>)}
    </div>
    <div style={{display:"flex",justifyContent:"flex-end",gap:10,marginTop:24}}><button className="btn btn-ghost" onClick={onClose}>Cancel</button><button className="btn btn-primary" onClick={submit} disabled={busy}>{busy?"Creating…":"Create Deal"}</button></div>
  </div></div>;
}

// ── Add User Modal ────────────────────────────────────────────────────────
function AddUserModal({onClose,onSave}) {
  const [form,setForm]=useState({name:"",email:"",role:"sales_rep",team:"UAE Sales"}); const [err,setErr]=useState(""); const [busy,setBusy]=useState(false);
  const submit=async()=>{ if(!form.name||!form.email){setErr("Name and email required.");return;} setBusy(true); try{await onSave(form);}catch(e){setErr(e.message);setBusy(false);} };
  return <div className="modal-bg" onClick={e=>e.target===e.currentTarget&&onClose()}><div className="modal">
    <div style={{fontFamily:"Syne,sans-serif",fontSize:18,fontWeight:700,marginBottom:24}}>Invite User</div>
    {err&&<div className="error-banner">{err}</div>}
    <div style={{display:"flex",flexDirection:"column",gap:16}}>
      {[{l:"Full Name",k:"name",type:"text"},{l:"Email",k:"email",type:"email"},{l:"Team",k:"team",type:"text"}].map(f=>(
        <div key={f.k}><label>{f.l}</label><input className="input" type={f.type} value={form[f.k]} onChange={e=>setForm(p=>({...p,[f.k]:e.target.value}))}/></div>))}
      <div><label>Role</label><select className="input" value={form.role} onChange={e=>setForm(p=>({...p,role:e.target.value}))}>{Object.entries(ROLES).filter(([k])=>k!=="super_admin").map(([k,v])=><option key={k} value={k}>{v}</option>)}</select></div>
      <div style={{background:"#0a0f1e",border:"1px solid #f59e0b33",borderRadius:10,padding:"12px 14px",fontSize:13,color:"#fbbf24"}}>⚠ Temp password <b>Omnes2026!</b> — user must change on first login.</div>
    </div>
    <div style={{display:"flex",gap:10,marginTop:24,justifyContent:"flex-end"}}><button className="btn btn-ghost" onClick={onClose}>Cancel</button><button className="btn btn-primary" onClick={submit} disabled={busy}>{busy?"Inviting…":"Send Invite"}</button></div>
  </div></div>;
}
